const p=(a,r=1)=>{const n=/^#?([a-f\d])([a-f\d])([a-f\d])$/i;a=a.replace(n,(f,c,d,u)=>c+c+d+d+u+u);const t=/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(a);if(!t)return`rgba(0, 0, 0, ${r})`;const[o,s,e]=[parseInt(t[1],16),parseInt(t[2],16),parseInt(t[3],16)];return`rgba(${o}, ${s}, ${e}, ${r})`},b=a=>{const r=a.replace("#","");if(r.length!==6)return"#1e293b";const n=parseInt(r.substring(0,2),16),t=parseInt(r.substring(2,4),16),o=parseInt(r.substring(4,6),16),s=(.299*n+.587*t+.114*o)/255,e=s>.6?"#1e293b":"#FFFFFF";return e==="#FFFFFF"&&s>.8?"#1e293b":e},F=(a,r=.55)=>{const n=/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(a.replace("#",""));if(!n)return"#fdba74";const t=Math.round(parseInt(n[1],16)*(1-r)+255*r),o=Math.round(parseInt(n[2],16)*(1-r)+255*r),s=Math.round(parseInt(n[3],16)*(1-r)+255*r);return"#"+[t,o,s].map(e=>Math.min(255,Math.max(0,e)).toString(16).padStart(2,"0")).join("")};export{p as h,F as l,b as s};
